  function routeKm(r){ if(!r) return 0; if(r.distance_km!=null && r.distance_km!=='' && !isNaN(parseFloat(r.distance_km))) return parseFloat(r.distance_km)||0; const meta=routeMeta(r); const buckets=[meta.portal_summary||{},meta.generated_plan_summary||{},meta.original_plan_summary||{},meta.plan_summary||{},meta.route_metrics||{},meta.metrics||{}]; for(const b of buckets){ if(!b) continue; if(b.suggestion_distance_km!=null && !isNaN(parseFloat(b.suggestion_distance_km))) return parseFloat(b.suggestion_distance_km)||0; if(b.distance_km!=null && !isNaN(parseFloat(b.distance_km))) return parseFloat(b.distance_km)||0; if(b.total_distance_km!=null && !isNaN(parseFloat(b.total_distance_km))) return parseFloat(b.total_distance_km)||0; } if(meta.distance_km!=null && !isNaN(parseFloat(meta.distance_km))) return parseFloat(meta.distance_km)||0; if(meta.total_distance_km!=null && !isNaN(parseFloat(meta.total_distance_km))) return parseFloat(meta.total_distance_km)||0; return 0; }
