  function renderOwnerRoutesSummary(){ if(!els.ownerRoutesSummary) return; const routes=sortedRoutes(state.routeAgenda); if(!els.owner||!els.owner.value){ els.ownerRoutesSummary.innerHTML='<div class="rp-panel-head" style="margin-bottom:8px"><div><h4 style="margin:0">Rotas atribuídas ao operativo</h4><p>Escolhe um operativo para ver a agenda de rotas já criadas, mesmo fora do filtro de data atual.</p></div><span class="rp-pill">Agenda</span></div><div class="rp-chart-empty">Seleciona um operativo para carregar a respetiva agenda de rotas.</div>'; return; } const months=availableRouteMonths(routes); if(state.ownerRoutesMonth!=='all' && months.indexOf(state.ownerRoutesMonth)<0) state.ownerRoutesMonth='all'; const filtered=state.ownerRoutesMonth==='all'?routes:routes.filter(r=>routeMonthKey(r)===state.ownerRoutesMonth); const totalKm=filtered.reduce((n,r)=>n+routeKm(r),0); const totalToll=filtered.reduce((n,r)=>n+routeToll(r),0); const totalStops=filtered.reduce((n,r)=>n+routeStops(r),0); const range=state.routeAgendaRange||agendaRange(); const perPage=10; const totalPages=Math.max(1,Math.ceil(filtered.length/perPage)); state.ownerRoutesPage=clampPage(state.ownerRoutesPage,totalPages); const paged=filtered.slice((state.ownerRoutesPage-1)*perPage,state.ownerRoutesPage*perPage); const monthOptions='<option value="all">Todos os meses</option>'+months.map(m=>`<option value="${esc(m)}" ${state.ownerRoutesMonth===m?'selected':''}>${esc(monthLabel(m))}</option>`).join(''); const list=paged.map(r=>`<button type="button" class="rp-route-summary-item ${String(r.id)===String(state.selectedRouteId)?'active':''}" data-open-route="${esc(r.id)}"><strong>${esc(r.date||'')}</strong><span><b>Rota #${esc(r.id)}</b><br><small>${esc(routeProject(r))} · ${esc(routeOwner(r))} · ${routeStops(r)} PDVs</small></span><span>${fmtKm(routeKm(r))}<br><small>${fmtEur(routeToll(r))}</small></span></button>`).join(''); const pages=filtered.length>perPage?`<div class="rp-table-meta"><div class="rp-meta">${filtered.length} rotas, página ${state.ownerRoutesPage} de ${totalPages}</div><div class="rp-pagination"><button type="button" class="rp-small" data-summary-page="${state.ownerRoutesPage-1}" ${state.ownerRoutesPage<=1?'disabled':''}>Anterior</button><button type="button" class="rp-small" data-summary-page="${state.ownerRoutesPage+1}" ${state.ownerRoutesPage>=totalPages?'disabled':''}>Seguinte</button></div></div>`:`<div class="rp-meta" style="margin-top:10px">${filtered.length} rotas visíveis.</div>`; els.ownerRoutesSummary.innerHTML=`<div class="rp-panel-head" style="margin-bottom:8px"><div><h4 style="margin:0">Rotas atribuídas ao operativo</h4><p>${esc(selectedText(els.owner,'Operativo'))} · ${esc(range.from)} a ${esc(range.to)} · independente do filtro diário atual.</p></div><span class="rp-pill">${routes.length} rotas</span></div><div class="rp-kpi-grid">${metric('Rotas atribuídas',filtered.length,'No mês selecionado')}${metric('PDVs em rota',totalStops,'Paragens planeadas')}${metric('Kms estimados',fmtKm(totalKm),'Total visível')}${metric('Portagens estimadas',fmtEur(totalToll),'Total visível')}${metric('Meses com rotas',months.length,'Agenda mensal')}</div><div class="rp-summary-controls"><label class="rp-meta">Vista mensal <select id="rpcp-summary-month">${monthOptions}</select></label><button type="button" class="rp-small primary" id="rpcp-summary-open-routes">Abrir calendário</button></div><div class="rp-route-summary-list">${list||'<div class="rp-chart-empty">Sem rotas criadas para este mês.</div>'}</div>${pages}`; els.ownerRoutesSummary.querySelectorAll('[data-open-route]').forEach(btn=>btn.addEventListener('click',()=>openRouteFromAgenda(btn.dataset.openRoute))); const sel=els.ownerRoutesSummary.querySelector('#rpcp-summary-month'); if(sel) sel.addEventListener('change',()=>{ state.ownerRoutesMonth=sel.value||'all'; state.ownerRoutesPage=1; if(state.ownerRoutesMonth!=='all'){ state.routeCalendarMonth=state.ownerRoutesMonth; state.routeListPage=1; } renderOwnerRoutesSummary(); renderRouteCalendar(); renderRouteList(); }); els.ownerRoutesSummary.querySelectorAll('[data-summary-page]').forEach(btn=>btn.addEventListener('click',()=>{ state.ownerRoutesPage=clampPage(btn.dataset.summaryPage,totalPages); renderOwnerRoutesSummary(); })); els.ownerRoutesSummary.querySelector('#rpcp-summary-open-routes')?.addEventListener('click',()=>switchPanel('routes')); }
  function renderRouteCalendar(){ if(!els.routeCalendar) return; const routes=sortedRoutes(state.routes); if(els.routeAgendaLabel) els.routeAgendaLabel.textContent=(els.owner&&els.owner.value)?'Agenda anual':'Período'; if(!routes.length){ els.routeCalendar.innerHTML='<div class="rp-chart-empty">Sem rotas para mostrar em calendário.</div>'; return; } const months=availableRouteMonths(routes); const selectedRoute=(state.selectedRouteId && routes.find(r=>String(r.id)===String(state.selectedRouteId))) || null; if(!state.routeCalendarMonth && selectedRoute && routeMonthKey(selectedRoute)) state.routeCalendarMonth=routeMonthKey(selectedRoute); if(!state.routeCalendarMonth || months.indexOf(state.routeCalendarMonth)<0) state.routeCalendarMonth=months[0]||''; const month=state.routeCalendarMonth; const monthRoutes=routes.filter(r=>routeMonthKey(r)===month); const [year,mon]=month.split('-').map(n=>parseInt(n,10)); const first=new Date(year,mon-1,1); const daysInMonth=new Date(year,mon,0).getDate(); const offset=(first.getDay()+6)%7; const byDate=new Map(); monthRoutes.forEach(r=>{ const d=String(r.date||''); if(!byDate.has(d)) byDate.set(d,[]); byDate.get(d).push(r); }); const cells=[]; for(let i=0;i<offset;i++) cells.push('<div class="rp-day-empty"></div>'); for(let day=1; day<=daysInMonth; day++){ const date=month+'-'+String(day).padStart(2,'0'); const items=byDate.get(date)||[]; if(!items.length){ cells.push('<div class="rp-day-empty"></div>'); continue; } const km=items.reduce((n,r)=>n+routeKm(r),0); const toll=items.reduce((n,r)=>n+routeToll(r),0); const stops=items.reduce((n,r)=>n+routeStops(r),0); const active=items.some(r=>String(r.id)===String(state.selectedRouteId)); cells.push(`<button type="button" class="rp-day-chip ${active?'active':''}" data-open-route="${esc(items[0].id)}" title="${esc(items.length+' rota(s), '+fmtKm(km)+', '+fmtEur(toll)+', '+stops+' PDVs')}"><span>${day}</span><small>${items.length} rota${items.length===1?'':'s'}<br>${fmtKm(km)} · ${fmtEur(toll)} · ${stops} PDVs</small></button>`); } const idx=months.indexOf(month); const monthOptions=months.map(m=>`<option value="${esc(m)}" ${m===month?'selected':''}>${esc(monthLabel(m))}</option>`).join(''); els.routeCalendar.innerHTML=`<div class="rp-calendar-controls"><button type="button" class="rp-small" data-cal-prev ${idx<=0?'disabled':''}>Anterior</button><select id="rpcp-route-month">${monthOptions}</select><button type="button" class="rp-small" data-cal-next ${idx>=months.length-1?'disabled':''}>Seguinte</button></div><div class="rp-month-card"><h5>${esc(monthLabel(month))} · ${monthRoutes.length} rota${monthRoutes.length===1?'':'s'}</h5><div class="rp-weekdays"><div class="rp-weekday">Seg</div><div class="rp-weekday">Ter</div><div class="rp-weekday">Qua</div><div class="rp-weekday">Qui</div><div class="rp-weekday">Sex</div><div class="rp-weekday">Sáb</div><div class="rp-weekday">Dom</div></div><div class="rp-month-days">${cells.join('')}</div></div>`; els.routeCalendar.querySelectorAll('[data-open-route]').forEach(btn=>btn.addEventListener('click',()=>openRouteFromAgenda(btn.dataset.openRoute))); const monthSel=els.routeCalendar.querySelector('#rpcp-route-month'); if(monthSel) monthSel.addEventListener('change',()=>{ state.routeCalendarMonth=monthSel.value||month; state.routeListPage=1; renderRouteCalendar(); renderRouteList(); }); els.routeCalendar.querySelector('[data-cal-prev]')?.addEventListener('click',()=>{ if(idx>0){ state.routeCalendarMonth=months[idx-1]; state.routeListPage=1; renderRouteCalendar(); renderRouteList(); } }); els.routeCalendar.querySelector('[data-cal-next]')?.addEventListener('click',()=>{ if(idx<months.length-1){ state.routeCalendarMonth=months[idx+1]; state.routeListPage=1; renderRouteCalendar(); renderRouteList(); } }); }
  async function openRouteFromAgenda(routeId){ const r=(state.routeAgenda||state.routes||[]).find(x=>String(x.id)===String(routeId)) || (state.routes||[]).find(x=>String(x.id)===String(routeId)); if(r&&r.date){ state.routeCalendarMonth=String(r.date).slice(0,7); state.ownerRoutesMonth=String(r.date).slice(0,7); state.routeListPage=1; setRouteDateLock(String(r.date), r.id); } switchPanel('routes'); await selectRoute(routeId,true,false); }
  async function loadRoutesRange(){ const cfg=paramsForRouteAgenda(); state.routeAgendaRange=cfg.range; const data=await j(api+'routes?'+cfg.params.toString()).catch(()=>({routes:[]})); const routes=sortedRoutes(Array.isArray(data.routes)?data.routes:[]); state.routeAgenda=routes; state.routes=routes; const months=availableRouteMonths(routes); if(state.routeCalendarMonth && months.indexOf(state.routeCalendarMonth)<0) state.routeCalendarMonth=''; if(!state.routeCalendarMonth && months.length) state.routeCalendarMonth=months[0]; if(state.selectedRouteId && state.routes.some(r=>String(r.id)===String(state.selectedRouteId))){ await selectRoute(state.selectedRouteId,false,false); } renderOwnerRoutesSummary(); renderRouteCalendar(); renderRouteList(); renderReports(); }
  function badge(status){ const cls=(status||'pending').replace(/[^a-z_]/gi,'_'); return `<span class="rp-badge ${cls}">${esc(status||'pending')}</span>`; }
  function trendDelta(current, previous, suffix=''){ const c=parseFloat(current||0)||0; const p=parseFloat(previous||0)||0; const d=+(c-p).toFixed(1); if(d>0) return `▲ +${d}${suffix}`; if(d<0) return `▼ ${d}${suffix}`; return `• 0${suffix}`; }
  function metric(label,val,small,delta){ return `<div class="rp-kpi"><span>${label}</span><strong>${val}</strong><small style="display:block;margin-top:6px;color:#64748b">${small||''}${delta?`<br><span style=\"color:#0f172a;font-weight:600\">${delta}</span>`:''}</small></div>`; }
  function renderKpis(stats){ const prev=stats?.previous_summary||{}; const rank=stats?.rankings||{}; els.kpis.innerHTML=[metric('Rotas',stats?.total_routes||0,'Total no período',trendDelta(stats?.total_routes||0, prev?.total_routes||0)),metric('Concluídas',stats?.completed_routes||0,'Rotas fechadas',trendDelta(stats?.completed_routes||0, prev?.completed_routes||0)),metric('Paragens',stats?.total_stops||0,'Execução acumulada',trendDelta(stats?.total_stops||0, prev?.total_stops||0)),metric('% Execução',(stats?.done_rate||0)+'%','Conclusão de paragens',trendDelta(stats?.done_rate||0, prev?.done_rate||0,'%')),metric('On time',stats?.on_time_rate==null?'n.d.':(stats.on_time_rate+'%'),'Dentro da janela horária'),metric('Média visita',stats?.avg_stop_minutes?stats.avg_stop_minutes+' min':'n.d.','Tempo médio por paragem'),metric('Top campanha',rank?.top_project||'n.d.',rank?.top_project_value?`${rank.top_project_value} paragens concluídas`:'Sem liderança no período'),metric('Top owner',rank?.top_owner||'n.d.',rank?.top_owner_value?`${rank.top_owner_value} paragens concluídas`:'Sem liderança no período')].join(''); }
  function renderCommercialKpis(commercial){ const cs=(commercial&&commercial.stats)||{}; if(els.commercialKpis){ els.commercialKpis.innerHTML=[metric('PDVs visíveis',cs.total_visible||0,'Resultado atual da base comercial'),metric('Com coordenadas',cs.with_coords||0,'Prontos para mapa e rota'),metric('Origem Google',cs.google_count||0,'Registos vindos de integração Google'),metric('Validados',cs.validated_count||0,'Qualidade confirmada no âmbito ativo')].join(''); } setHeroMetric('rpcp-hero-scope',selectedText(els.client,'Todos os clientes')+' / '+selectedText(els.project,'Todas as campanhas'),'Escopo operacional sincronizado com o portal.'); setHeroMetric('rpcp-hero-commercial',cs.total_visible||0,`PDVs visíveis, ${cs.google_count||0} origem Google.`); setHeroMetric('rpcp-hero-validation',`${cs.validated_count||0} / ${cs.with_coords||0}`,'Validados e com coordenadas prontos para operação.'); setHeroMetric('rpcp-hero-period',`${esc(els.from?.value||'')} a ${esc(els.to?.value||'')}`,'Janela temporal ativa no resumo executivo.'); }
  function renderChart(rows){ rows=Array.isArray(rows)?rows:[]; if(!rows.length){ els.chart.innerHTML='<div class="rp-chart-empty">Sem dados no período selecionado.</div>'; return; } const values=rows.map(r=>parseFloat(r.done_rate||0)||0); const max=Math.max(100,...values); const barW=rows.length>12?34:50; const gap=14; const width=Math.max(380, rows.length*(barW+gap)+40); const height=240; const bars=rows.map((r,i)=>{ const x=20+i*(barW+gap); const val=parseFloat(r.done_rate||0)||0; const h=Math.max(8,Math.round((val/max)*160)); const y=190-h; const label=String(r.date||'').slice(5); return `<g><rect x="${x}" y="${y}" width="${barW}" height="${h}" rx="12" fill="<?php echo esc_attr($theme['primary']); ?>"></rect><text x="${x+barW/2}" y="206" text-anchor="middle" font-size="11" fill="#475569">${esc(label)}</text><text x="${x+barW/2}" y="${Math.max(18,y-8)}" text-anchor="middle" font-size="11" fill="#0f172a">${val}%</text></g>`; }).join(''); els.chart.innerHTML=`<svg viewBox="0 0 ${width} ${height}" role="img" aria-label="Execução por dia"><line x1="14" y1="190" x2="${width-12}" y2="190" stroke="#cbd5e1" stroke-width="1"></line>${bars}</svg>`; }
  function paginateRows(rows,page,perPage){ const total=Math.max(1,Math.ceil((rows.length||0)/perPage)); const safe=Math.min(Math.max(parseInt(page||1,10)||1,1),total); return {page:safe,total,paged:rows.slice((safe-1)*perPage,safe*perPage)}; }
  function renderPagination(container,page,total,onChange){ if(!container) return; if(total<=1){ container.innerHTML=''; return; } const prevDisabled=page<=1?'disabled':''; const nextDisabled=page>=total?'disabled':''; container.innerHTML=`<button type="button" class="rp-small" data-page="${page-1}" ${prevDisabled}>Anterior</button><span class="rp-meta">Página ${page} de ${total}</span><button type="button" class="rp-small" data-page="${page+1}" ${nextDisabled}>Seguinte</button>`; container.querySelectorAll('[data-page]').forEach(btn=>btn.addEventListener('click',()=>onChange(parseInt(btn.dataset.page||'1',10)||1))); }
  function renderRoutesTable(rows,page=1){ rows=Array.isArray(rows)?rows:[]; const view=paginateRows(rows,page,8); if(els.routesMeta) els.routesMeta.textContent=(rows.length||0)+' registos'; if(!view.paged.length){ els.routesTable.innerHTML='<tr><td colspan="8">Sem dados.</td></tr>'; renderPagination(els.routesPagination,1,1,()=>{}); return; } els.routesTable.innerHTML=view.paged.map(x=>`<tr><td>${esc(x.date||'')}</td><td>${esc(x.project_name||'')}</td><td>${esc(x.user_name||x.owner_name||'')}</td><td>#${esc(x.route_id||'')}</td><td>${badge(x.route_status||'')}</td><td>${esc(x.stops||0)}</td><td>${esc(x.stops_done||0)}</td><td>${esc(x.done_rate||0)}%</td></tr>`).join(''); renderPagination(els.routesPagination,view.page,view.total,next=>renderRoutesTable(rows,next)); }
  function analyticsSvgBar(series){ const values=series.map(r=>parseFloat(r.value||0)||0); const max=Math.max(1,...values); const barW=series.length>10?28:42; const gap=12; const width=Math.max(360, series.length*(barW+gap)+30); const height=220; const bars=series.map((r,i)=>{ const x=16+i*(barW+gap); const val=parseFloat(r.value||0)||0; const h=Math.max(8,Math.round((val/max)*150)); const y=180-h; return `<g><rect x="${x}" y="${y}" width="${barW}" height="${h}" rx="10" fill="<?php echo esc_attr($theme['primary']); ?>"></rect><text x="${x+barW/2}" y="195" text-anchor="middle" font-size="11" fill="#475569">${esc(String(r.label||'').slice(0,10))}</text><text x="${x+barW/2}" y="${Math.max(18,y-6)}" text-anchor="middle" font-size="11" fill="#0f172a">${val}</text></g>`; }).join(''); return `<svg viewBox="0 0 ${width} ${height}" role="img"><line x1="10" y1="180" x2="${width-10}" y2="180" stroke="#cbd5e1" stroke-width="1"></line>${bars}</svg>`; }
  function analyticsSvgLine(series){ const values=series.map(r=>parseFloat(r.value||0)||0); const max=Math.max(1,...values); const width=Math.max(420, series.length*70); const height=220; const points=series.map((r,i)=>{ const x=30+(i*((width-60)/Math.max(1,series.length-1))); const y=180-((parseFloat(r.value||0)||0)/max)*130; return {x,y,label:r.label,val:r.value}; }); const poly=points.map(p=>`${p.x},${p.y}`).join(' '); const nodes=points.map(p=>`<g><circle cx="${p.x}" cy="${p.y}" r="4" fill="<?php echo esc_attr($theme['primary']); ?>"></circle><text x="${p.x}" y="195" text-anchor="middle" font-size="11" fill="#475569">${esc(String(p.label||'').slice(0,10))}</text><text x="${p.x}" y="${Math.max(18,p.y-8)}" text-anchor="middle" font-size="11" fill="#0f172a">${esc(p.val)}</text></g>`).join(''); return `<svg viewBox="0 0 ${width} ${height}" role="img"><line x1="20" y1="180" x2="${width-20}" y2="180" stroke="#cbd5e1" stroke-width="1"></line><polyline fill="none" stroke="<?php echo esc_attr($theme['primary']); ?>" stroke-width="3" points="${poly}"></polyline>${nodes}</svg>`; }
  function analyticsSvgPie(series){ const total=series.reduce((n,x)=>n+(parseFloat(x.value||0)||0),0)||1; let start=0; const cx=120, cy=120, r=78; const palette=['#0f766e','#2563eb','#7c3aed','#ea580c','#dc2626','#16a34a','#0891b2','#9333ea']; const slices=series.map((row,idx)=>{ const value=parseFloat(row.value||0)||0; const angle=(value/total)*Math.PI*2; const end=start+angle; const x1=cx+r*Math.cos(start), y1=cy+r*Math.sin(start), x2=cx+r*Math.cos(end), y2=cy+r*Math.sin(end); const large=angle>Math.PI?1:0; const path=`M ${cx} ${cy} L ${x1} ${y1} A ${r} ${r} 0 ${large} 1 ${x2} ${y2} Z`; const item=`<path d="${path}" fill="${palette[idx%palette.length]}"></path>`; start=end; return item; }).join(''); const legend=series.map((row,idx)=>`<div style="display:flex;align-items:center;gap:8px;margin:4px 0"><span style="display:inline-block;width:10px;height:10px;border-radius:999px;background:${palette[idx%palette.length]}"></span><span>${esc(row.label)}: ${esc(row.value)}</span></div>`).join(''); return `<div style="display:grid;grid-template-columns:240px 1fr;gap:16px;align-items:center"><svg viewBox="0 0 240 240" role="img">${slices}</svg><div>${legend}</div></div>`; }
  function renderAnalytics(stats){
    if(!els.analyticsKpis || !els.analyticsChart || !els.analyticsTables) return;
    const s=stats||{}; const prev=s?.previous_summary||{}; const rank=s?.rankings||{};
    const baseKpis=[metric('Rotas',s?.total_routes||0,'Total no período',trendDelta(s?.total_routes||0,prev?.total_routes||0)),metric('Concluídas',s?.completed_routes||0,'Rotas fechadas',trendDelta(s?.completed_routes||0,prev?.completed_routes||0)),metric('Paragens',s?.total_stops||0,'Execução acumulada',trendDelta(s?.total_stops||0,prev?.total_stops||0)),metric('% Execução',(s?.done_rate||0)+'%','Conclusão de paragens',trendDelta(s?.done_rate||0,prev?.done_rate||0,'%')),metric('Top campanha',rank?.top_project||'n.d.',rank?.top_project_value?`${rank.top_project_value} paragens concluídas`:'Sem liderança no período'),metric('Top owner',rank?.top_owner||'n.d.',rank?.top_owner_value?`${rank.top_owner_value} paragens concluídas`:'Sem liderança no período')];
    const analytics=s.form_analytics||{}; const metrics=Array.isArray(analytics.metrics)?analytics.metrics:[]; const dashboards=Array.isArray(analytics.dashboards)?analytics.dashboards:[];
    const dashboardById={}; dashboards.forEach(d=>{dashboardById[String(d.id||0)]=d;});
    metrics.forEach(m=>{const id=String(m.dashboard_id||0); if(!dashboardById[id]) dashboardById[id]={id:m.dashboard_id||0,title:m.dashboard_title||'Analytics operacional',description:'',layout_type:'mixed'};});
    const dashList=Object.values(dashboardById);
    const kpiMetrics=metrics.filter(m=>m.chart_type==='kpi'||String(m.show_kpi||'0')==='1');
    const kpis=kpiMetrics.map(m=>metric(m.metric_label,m.value==null?'Sem dados':m.value,m.note||m.aggregation||''));
    els.analyticsKpis.innerHTML=(kpis.length?kpis:baseKpis).join('');
    if(!dashList.length){
      const rows=Array.isArray(s.by_day)?s.by_day:[];
      if(!rows.length){ els.analyticsChart.innerHTML='<div class="rp-chart-empty">Sem dashboards analíticos configurados para este âmbito.</div>'; els.analyticsTables.innerHTML='<div class="rp-chart-empty">Cria dashboards no Centro de Atribuições para o cliente ver a estrutura mesmo antes de existirem respostas.</div>'; return; }
      const renderFallbackPage=(page)=>{ const view=paginateRows(rows,page,10); const body=view.paged.map(x=>`<tr><td>${esc(x.date||'')}</td><td>${esc(x.project_name||'')}</td><td>${esc(x.user_name||x.owner_name||'')}</td><td>#${esc(x.route_id||'')}</td><td>${badge(x.route_status||'')}</td><td>${esc(x.stops||0)}</td><td>${esc(x.stops_done||0)}</td><td>${esc(x.done_rate||0)}%</td></tr>`).join(''); els.analyticsTables.innerHTML='<div class="rp-table-wrap"><table><thead><tr><th>Data</th><th>Campanha</th><th>Operativo</th><th>Rota</th><th>Status</th><th>Paragens</th><th>Done</th><th>Execução</th></tr></thead><tbody>'+body+'</tbody></table></div><div class="rp-table-meta"><div class="rp-meta">'+rows.length+' registos</div><div class="rp-pagination" id="rpcp-analytics-fallback-pagination"></div></div>'; renderPagination(root.querySelector('#rpcp-analytics-fallback-pagination'),view.page,view.total,renderFallbackPage); };
      els.analyticsChart.innerHTML=analyticsSvgBar(rows.map(r=>({label:String(r.date||'').slice(5),value:parseFloat(r.done_rate||0)||0}))); renderFallbackPage(1); return;
    }
    function metricVisual(m){ let inner=''; const series=Array.isArray(m.series)?m.series:[]; if(m.chart_type==='line'){ inner=series.length?analyticsSvgLine(series):''; } else if(m.chart_type==='bar'){ inner=series.length?analyticsSvgBar(series):''; } else if(m.chart_type==='pie'){ inner=series.length?analyticsSvgPie(series):''; } return `<div class="rp-subcard" style="margin-bottom:16px"><div class="rp-panel-head" style="margin-bottom:8px"><div><h4 style="margin:0">${esc(m.metric_label||m.metric_key||'Métrica')}</h4><p>${esc((m.aggregation||'')+' · '+(m.dimension||'')+(m.store_group_name?' · '+m.store_group_name:''))}</p></div><span class="rp-pill">${esc(m.chart_type||'')}</span></div>${inner||'<div class="rp-chart-empty">Sem dados no período selecionado.</div>'}</div>`; }
    els.analyticsChart.innerHTML=dashList.map(d=>{ const id=String(d.id||0); const group=metrics.filter(m=>String(m.dashboard_id||0)===id); const visual=group.filter(m=>m.chart_type!=='kpi' && m.chart_type!=='table'); return `<section class="rp-subcard" style="margin-bottom:18px"><div class="rp-panel-head" style="margin-bottom:10px"><div><h4 style="margin:0">${esc(d.title||'Dashboard')}</h4><p>${esc(d.description||'Quadro analítico configurado no Centro de Atribuições.')}</p></div><span class="rp-pill">Dashboard</span></div>${visual.map(metricVisual).join('')||'<div class="rp-chart-empty">Dashboard configurado sem gráficos ativos. As tabelas continuam disponíveis.</div>'}</section>`; }).join('');
