  function renderCampaignOwnerFilter(){ if(!els.campaignOwner) return; const current=els.campaignOwner.value||''; const users=Array.isArray(state.campaign.users)?state.campaign.users:[]; els.campaignOwner.innerHTML='<option value="">Todos os operativos</option>'+users.map(u=>`<option value="${parseInt(u.ID||u.id||0,10)}">${esc(u.display_name||u.label||('User #'+(u.ID||u.id||'')))}</option>`).join(''); if(current && Array.from(els.campaignOwner.options).some(o=>String(o.value)===String(current))) els.campaignOwner.value=current; }
  function renderCampaignPdvs(){ if(!els.campaignTable) return; const rows=Array.isArray(state.campaign.rows)?state.campaign.rows:[]; const sum=state.campaign.summary||{}; if(els.campaignKpis){ els.campaignKpis.innerHTML=[metric('PDVs na campanha',sum.total||rows.length,'Âmbito atual'),metric('Ativos',sum.active||0,'Com estado ativo'),metric('Com operativo',sum.with_owner||0,'Atribuição individual'),metric('Com coordenadas',sum.with_coords||0,'Prontos para rota'),metric('Rotas já criadas',sum.routes_count||0,'No âmbito selecionado'),metric('Kms rotas criadas',fmtKm(sum.routes_km||0),'Estimativa atual')].join(''); }
    const per=(state.campaign.perPage||25); if(els.campaignMeta) els.campaignMeta.textContent=(sum.filtered||rows.length)+' PDVs · '+per+' por página · página '+(state.campaign.page||1)+'/'+(state.campaign.totalPages||1);
    if(!rows.length){ els.campaignTable.innerHTML='<tr><td colspan="10"><div class="rp-campaign-empty">Sem PDVs ligados à campanha ou aos filtros atuais. Confirma o cliente/campanha no topo ou associa PDVs no BO Campanhas PDV.</div></td></tr>'; renderPagination(els.campaignPagination,1,1,()=>{}); return; }
    els.campaignTable.innerHTML=rows.map(row=>{ const linkId=parseInt(row.link_id||0,10); const hasAdvanced=!!(row.min_gap_days||row.max_gap_days||row.preferred_weekdays||row.blocked_weekdays||row.time_window_start||row.time_window_end||parseInt(row.allow_auto_reschedule??1,10)!==1||parseInt(row.allow_overtime||0,10)||row.rule_notes); const loc=[row.address,row.postal_code,row.city].filter(Boolean).join(' · '); const freq=String(row.visit_frequency||'weekly'); return `<tr class="rp-campaign-row" data-link-id="${linkId}" data-location-id="${escAttr(row.location_id||row.id||'')}"><td><strong>${esc(row.name||'')}</strong><div class="rp-meta">${esc(row.phone||'')}</div></td><td>${esc(row.project_name||'')}<div class="rp-meta">${esc(row.client_name||'')}</div></td><td>${esc(row.city||'')}<div class="rp-meta">${esc(loc)}</div></td><td><select class="owner-select" data-campaign-field="assigned_to">${usersOptions(row.assigned_to)}</select></td><td><div class="rp-inline-fields"><select data-campaign-field="visit_frequency"><option value="weekly" ${freq==='weekly'?'selected':''}>Semanal</option><option value="monthly" ${freq==='monthly'?'selected':''}>Mensal</option></select><input class="mini-input" type="number" min="1" max="7" title="Repetição" data-campaign-field="frequency_count" value="${escAttr(row.frequency_count||1)}"></div></td><td><div class="rp-inline-fields"><input class="mini-input" type="number" min="0" max="360" data-campaign-field="visit_duration_min" value="${escAttr(row.visit_duration_min||45)}"><span class="rp-meta">min</span></div></td><td><input class="mini-input" type="number" min="0" max="999" data-campaign-field="priority" value="${escAttr(row.priority||0)}"></td><td class="rp-campaign-rule"><details><summary>${hasAdvanced?'Configurada':'Padrão'}</summary><div><label>Intervalo mín.<br><input class="mini-input" type="number" min="0" max="31" data-campaign-field="min_gap_days" value="${escAttr(row.min_gap_days||0)}"> dias</label><label>Intervalo máx.<br><input class="mini-input" type="number" min="0" max="90" data-campaign-field="max_gap_days" value="${escAttr(row.max_gap_days||0)}"> dias</label><label style="grid-column:1/-1">Dias preferenciais<br><input type="text" data-campaign-field="preferred_weekdays" value="${escAttr(row.preferred_weekdays||'')}" placeholder="1,2,3,4,5"><span class="rp-meta">1=Seg, 7=Dom</span></label><label style="grid-column:1/-1">Dias bloqueados<br><input type="text" data-campaign-field="blocked_weekdays" value="${escAttr(row.blocked_weekdays||'')}" placeholder="6,7"></label><label>Janela início<br><input type="time" data-campaign-field="time_window_start" value="${escAttr(row.time_window_start||'')}"></label><label>Janela fim<br><input type="time" data-campaign-field="time_window_end" value="${escAttr(row.time_window_end||'')}"></label><label style="grid-column:1/-1"><input type="checkbox" data-campaign-field="allow_auto_reschedule" ${parseInt(row.allow_auto_reschedule??1,10)?'checked':''}> reagendamento automático</label><label style="grid-column:1/-1"><input type="checkbox" data-campaign-field="allow_overtime" ${parseInt(row.allow_overtime||0,10)?'checked':''}> permitir horas extra</label><label style="grid-column:1/-1">Notas<br><textarea rows="2" data-campaign-field="rule_notes">${esc(row.rule_notes||'')}</textarea></label></div></details></td><td><div class="rp-state-stack"><label><input type="checkbox" data-campaign-field="is_active" ${parseInt(row.campaign_active??row.is_active??1,10)?'checked':''}> ativo</label><select data-campaign-field="status"><option value="active" ${String(row.campaign_status||'active')==='active'?'selected':''}>active</option><option value="paused" ${String(row.campaign_status||'')==='paused'?'selected':''}>paused</option></select></div></td><td><button type="button" class="rp-small" data-campaign-routes="${escAttr(row.location_id||row.id||'')}">Ver rotas</button></td></tr>`; }).join('');
    els.campaignTable.querySelectorAll('[data-campaign-field]').forEach(el=>{ const ev=(el.type==='checkbox'||el.tagName==='SELECT')?'change':'input'; el.addEventListener(ev,()=>markCampaignDirty(el.closest('[data-link-id]'))); });
    els.campaignTable.querySelectorAll('[data-campaign-routes]').forEach(btn=>btn.addEventListener('click',async()=>{ const loc=btn.dataset.campaignRoutes||''; if(els.location){ els.location.value=loc; syncLocationSearchText(); renderLocationOptions(); } state.selectedRouteId=0; state.selectedRoute=null; state.routeListPage=1; switchPanel('routes'); await loadPortal(true); }));
    renderPagination(els.campaignPagination,state.campaign.page||1,state.campaign.totalPages||1,next=>{ state.campaign.page=next; loadCampaignPdvs(true); }); ensurePortalTableScroll(); }
  function setCampaignButtonLoading(btn, loading, text){ if(!btn) return; if(loading){ btn.dataset.oldText=btn.textContent||''; btn.disabled=true; btn.textContent=text||'A processar...'; } else { btn.disabled=false; if(btn.dataset.oldText){ btn.textContent=btn.dataset.oldText; delete btn.dataset.oldText; } } }
  function collectVisibleCampaignPayloads(force=false){ const rows=els.campaignTable?Array.from(els.campaignTable.querySelectorAll('[data-link-id]')):[]; const payloads={}; rows.forEach(row=>{ const id=row.dataset.linkId||''; if(!id) return; if(force || row.classList.contains('is-dirty') || (state.campaign.dirty&&state.campaign.dirty[id])) payloads[id]=campaignRowPayload(row); }); return payloads; }
  async function loadCampaignPdvs(withStatus=false){
    if(!els.campaignTable) return;
    const btn=els.campaignRefresh||root.querySelector('#rpcp-campaign-refresh');
    try{
      if(withStatus){ setStatus('A atualizar PDVs da campanha...'); setCampaignButtonLoading(btn,true,'A atualizar...'); }
      const p=paramsForCampaignPdvs(); p.set('_', String(Date.now()));
      const data=await j(api+'campaign-pdvs?'+p.toString());
      state.campaign.rows=Array.isArray(data.rows)?data.rows:[];
      state.campaign.users=Array.isArray(data.users)?data.users:[];
      state.campaign.summary=data.summary||{};
      state.campaign.page=parseInt(data.page||state.campaign.page||1,10)||1;
      state.campaign.totalPages=parseInt(data.total_pages||1,10)||1;
      state.campaign.dirty={};
      if(els.campaignDirty) els.campaignDirty.classList.remove('active');
      renderCampaignOwnerFilter();
      renderCampaignPdvs();
      if(withStatus) setStatus('PDVs da campanha atualizados.');
    }catch(err){
      setStatus(err.message||'Falha ao atualizar PDVs da campanha.');
    }finally{
      if(withStatus) setCampaignButtonLoading(btn,false);
    }
  }
  async function saveCampaignPdvs(forceVisible=false){
    const btn=els.campaignSave||root.querySelector('#rpcp-campaign-save');
    let payloads=Object.assign({}, state.campaign.dirty||{});
    if(forceVisible || !Object.keys(payloads).length) payloads=Object.assign(payloads, collectVisibleCampaignPayloads(forceVisible || !Object.keys(payloads).length));
    const ids=Object.keys(payloads||{}).filter(Boolean);
    if(!ids.length){ setStatus('Sem alterações por guardar nos PDVs.'); return; }
    setCampaignButtonLoading(btn,true,'A guardar...');
    setStatus('A guardar alterações dos PDVs...');
    let ok=0;
    try{
      for(const id of ids){
        await j(api+'campaign-pdvs/'+encodeURIComponent(id),{method:'PATCH',headers:{'Content-Type':'application/json','X-WP-Nonce':nonce},body:JSON.stringify(payloads[id])});
        ok++;
      }
      state.campaign.dirty={};
      if(els.campaignDirty) els.campaignDirty.classList.remove('active');
      if(els.campaignTable) els.campaignTable.querySelectorAll('.is-dirty').forEach(row=>row.classList.remove('is-dirty'));
      setStatus(ok+' PDV'+(ok===1?'':'s')+' atualizado'+(ok===1?'':'s')+'.');
      await loadCampaignPdvs(false);
      await loadRoutesRange();
    }catch(err){
      setStatus(err.message||'Falha ao guardar PDVs.');
    }finally{
      setCampaignButtonLoading(btn,false);
    }
  }
  function renderRouteList(){ if(!els.routeList) return; const all=sortedRoutes(state.routes); const month=state.routeCalendarMonth||''; const routes=month?all.filter(r=>routeMonthKey(r)===month):all; if(els.routeListMeta) els.routeListMeta.textContent=routes.length+' rotas'+(month?' em '+monthLabel(month):''); if(!routes.length){ els.routeList.innerHTML='<div class="rp-chart-empty">Sem rotas encontradas para a agenda atual.</div>'; renderPagination(els.routeListPagination,1,1,()=>{}); return; } const perPage=8; const view=paginateRows(routes,state.routeListPage,perPage); state.routeListPage=view.page; els.routeList.innerHTML=view.paged.map(r=>`<button type="button" class="rp-route-item ${String(r.id)===String(state.selectedRouteId)?'active':''}" data-route="${esc(r.id)}"><div class="rp-kicker">${esc(r.date||'')}</div><h4>Rota #${esc(r.id)} · ${fmtKm(routeKm(r))} · ${fmtEur(routeToll(r))}</h4><div class="rp-meta">${esc(r.status||'planned')} · ${esc(routeProject(r))} · ${esc(routeOwner(r))} · ${routeStops(r)} PDVs</div></button>`).join(''); renderPagination(els.routeListPagination,view.page,view.total,next=>{ state.routeListPage=next; renderRouteList(); }); els.routeList.querySelectorAll('[data-route]').forEach(btn=>btn.addEventListener('click',()=>openRouteFromAgenda(btn.dataset.route))); }
  function exportUrl(format){ const p=new URLSearchParams(); p.set('action','routespro_export_submissions'); p.set('_wpnonce', exportNonce); if(els.client&&els.client.value) p.set('client_id',els.client.value); if(els.project&&els.project.value) p.set('project_id',els.project.value); if(els.owner&&els.owner.value) p.set('owner_user_id',els.owner.value); if(els.location&&els.location.value) p.set('location_id',els.location.value); if(els.from&&els.from.value) p.set('date_from',els.from.value); if(els.to&&els.to.value) p.set('date_to',els.to.value); if(state.selectedRouteId) p.set('route_id',state.selectedRouteId); p.set('format',format); return '<?php echo esc_url(admin_url('admin-post.php')); ?>?'+p.toString(); }
  async function loadReports(){ const p=new URLSearchParams(); if(els.client&&els.client.value) p.set('client_id',els.client.value); if(els.project&&els.project.value) p.set('project_id',els.project.value); if(els.owner&&els.owner.value) p.set('owner_user_id',els.owner.value); if(els.location&&els.location.value) p.set('location_id',els.location.value); if(els.from&&els.from.value) p.set('date_from',els.from.value); if(els.to&&els.to.value) p.set('date_to',els.to.value); if(state.selectedRouteId) p.set('route_id',state.selectedRouteId); p.set('limit','500'); state.reports=await j(api+'form-submissions?'+p.toString()).catch(()=>({rows:[],columns:[]})); renderReports(); refreshExportLinks(); }
  function renderReports(page=1){ const cols=[{key:'route',label:'Rota'},{key:'stop',label:'Paragem'},{key:'client',label:'Cliente'},{key:'project',label:'Campanha / Projeto'},{key:'owner',label:'Operativo'},{key:'submitter',label:'Submetido por'},{key:'date',label:'Data'},{key:'status',label:'Status'}].concat((state.reports.columns||[]).map(c=>({key:c.key,label:c.label}))); if(els.reportHead) els.reportHead.innerHTML='<tr>'+cols.map(c=>`<th>${esc(c.label||'')}</th>`).join('')+'</tr>'; const rows=Array.isArray(state.reports.rows)?state.reports.rows:[]; if(els.reportsMeta) els.reportsMeta.textContent=(rows.length||0)+' registos'; const view=paginateRows(rows,page,10); if(!view.paged.length){ els.reportTable.innerHTML=`<tr><td colspan="${cols.length}">Sem relatórios para os filtros atuais.</td></tr>`; renderPagination(els.reportsPagination,1,1,()=>{}); return; } els.reportTable.innerHTML=view.paged.map(r=>{ const fixed=[`#${esc(r.route_id||r.joined_route_id||'')}`, `${esc(r.route_stop_id||r.stop_row_id||'')}${r.location_name?` · ${esc(r.location_name)}`:''}`, esc(r.client_name||''), esc(r.project_name||''), esc(r.owner_name||''), esc(r.user_name||''), esc(r.submitted_at||''), esc(r.status||'')]; const dynamic=(state.reports.columns||[]).map(c=>esc((r.answers&&r.answers[c.key])||'—')); return '<tr>'+fixed.concat(dynamic).map(v=>`<td>${v||'—'}</td>`).join('')+'</tr>'; }).join(''); renderPagination(els.reportsPagination,view.page,view.total,next=>renderReports(next)); }
  function renderRouteDetail(){ const route=state.selectedRoute; if(!route){ els.routeDetail.innerHTML='<div class="rp-chart-empty">Seleciona uma rota para ver e editar o detalhe.</div>'; return; } const stops=Array.isArray(route.stops)?route.stops:[]; const statusOptions=['planned','draft','in_progress','done','completed','cancelled']; const doneCount=stops.filter(s=>['done','completed'].includes(String(s.status||'').toLowerCase())).length; const failedCount=stops.filter(s=>String(s.status||'').toLowerCase()==='failed').length; const coordsCount=stops.filter(s=>Number.isFinite(parseFloat(s.lat))&&Number.isFinite(parseFloat(s.lng))).length; const pendingCount=Math.max(0, stops.length-doneCount-failedCount); const doneRate=stops.length?Math.round((doneCount/stops.length)*100):0; els.routeDetail.innerHTML=`<div class="rp-panel-head" style="margin-bottom:8px"><div><h3 style="font-size:22px">Rota #${esc(route.id)}</h3><p>Data ${esc(route.date||'')} · ${esc(route.status||'planned')} · ${stops.length} paragens</p></div><span class="rp-pill">Editor rápido</span></div><div class="rp-kpi-grid" style="margin-bottom:14px">${metric('Paragens',stops.length,'Total carregado')}${metric('Concluídas',doneCount,'Estado done ou completed')}${metric('Pendentes',pendingCount,'Ainda por executar')}${metric('% rota',doneRate+'%','Execução atual da rota')}${metric('Falhadas',failedCount,'Paragens com falha operacional')}${metric('Com coordenadas',coordsCount,'Pontos prontos para navegação')}${metric('Kms estimados',fmtKm(routeKm(route)),'Total estimado da rota')}${metric('Portagens estimadas',fmtEur(routeToll(route)),'Estimativa operacional')}${metric('Status',esc(route.status||'planned'),'Estado atual da rota')}</div><div class="rp-row" style="display:flex;gap:10px;flex-wrap:wrap;align-items:center"><select id="rpcp-route-status">${statusOptions.map(s=>`<option value="${s}" ${String(route.status||'')===s?'selected':''}>${s}</option>`).join('')}</select><button type="button" class="rp-small primary" id="rpcp-save-route-status">Atualizar estado</button><button type="button" class="rp-small alt" id="rpcp-open-route-maps">Abrir no Maps</button><button type="button" class="rp-small" id="rpcp-reload-route">Recarregar rota</button></div><div class="rp-stop-list">${stops.map((stop,idx)=>`<div class="rp-stop" data-stop="${stop.id}"><div class="rp-stop-no">${idx+1}</div><div><h4 style="margin:0 0 6px">${esc(stop.location_name||'PDV')}</h4><div class="rp-meta">${esc(stop.address||'')}</div><div style="margin-top:8px">${badge(stop.status||'pending')}</div><div class="rp-stop-actions"><button type="button" class="rp-small" data-move="up" data-stop="${stop.id}" aria-label="Subir paragem">▲</button><button type="button" class="rp-small" data-move="down" data-stop="${stop.id}" aria-label="Descer paragem">▼</button><button type="button" class="rp-small primary" data-stop-status="done" data-stop="${stop.id}">Marcar done</button><button type="button" class="rp-small" data-stop-status="pending" data-stop="${stop.id}">Pendente</button></div></div></div>`).join('') || '<div class="rp-chart-empty">Sem paragens nesta rota.</div>'}</div>`;
    const moveStop=(stopId,direction)=>{ const arr=route.stops||[]; const idx=arr.findIndex(s=>String(s.id)===String(stopId)); if(idx<0) return; const swap=direction==='up'?idx-1:idx+1; if(swap<0||swap>=arr.length) return; const temp=arr[idx]; arr[idx]=arr[swap]; arr[swap]=temp; arr.forEach((s,i)=>{ s.seq=i+1; }); renderRouteDetail(); renderReports(); };
    els.routeDetail.querySelector('#rpcp-save-route-status')?.addEventListener('click', async()=>{ try{ await j(api+'routes/'+route.id,{method:'PATCH',headers:{'Content-Type':'application/json','X-WP-Nonce':nonce},body:JSON.stringify({status:els.routeDetail.querySelector('#rpcp-route-status').value})}); setStatus('Estado da rota atualizado.'); await selectRoute(route.id,false); await loadPortal(false); }catch(err){ setStatus(err.message||'Falha ao atualizar rota.'); } });
    els.routeDetail.querySelector('#rpcp-open-route-maps')?.addEventListener('click', ()=>{ const pts=(route.stops||[]).map(s=> Number.isFinite(parseFloat(s.lat))&&Number.isFinite(parseFloat(s.lng)) ? `${s.lat},${s.lng}` : (s.address||s.location_name||'')).filter(Boolean); if(pts.length<2){ return setStatus('São precisos pelo menos dois pontos válidos para abrir navegação.'); } const origin=pts[0], destination=pts[pts.length-1], mids=pts.slice(1,-1).slice(0,23); let url='https://www.google.com/maps/dir/?api=1&travelmode=driving&origin='+encodeURIComponent(origin)+'&destination='+encodeURIComponent(destination); if(mids.length) url+='&waypoints='+encodeURIComponent(mids.join('|')); window.open(url,'_blank','noopener'); });
    els.routeDetail.querySelector('#rpcp-reload-route')?.addEventListener('click', ()=>selectRoute(route.id,true));
    els.routeDetail.querySelectorAll('[data-move]').forEach(btn=>btn.addEventListener('click', ()=>moveStop(btn.dataset.stop,btn.dataset.move)));
    els.routeDetail.querySelectorAll('[data-stop-status]').forEach(btn=>btn.addEventListener('click', async()=>{ try{ await j(api+'stops/'+btn.dataset.stop,{method:'PATCH',headers:{'Content-Type':'application/json','X-WP-Nonce':nonce},body:JSON.stringify({status:btn.dataset.stopStatus})}); setStatus('Estado da paragem atualizado.'); await selectRoute(route.id,false); await loadPortal(false); }catch(err){ setStatus(err.message||'Falha ao atualizar paragem.'); } }));
    const persistSequence=async()=>{ if(!canManage || !Array.isArray(route.stops)) return; for(let i=0;i<route.stops.length;i++){ const stop=route.stops[i]; await j(api+'stops/'+stop.id,{method:'PATCH',headers:{'Content-Type':'application/json','X-WP-Nonce':nonce},body:JSON.stringify({seq:i+1})}); } setStatus('Ordem das paragens gravada.'); };
    els.routeDetail.querySelectorAll('[data-move]').forEach(btn=>btn.addEventListener('click', ()=>setTimeout(()=>persistSequence().catch(err=>setStatus(err.message||'Falha ao gravar ordem.')),40)));
  }
  async function selectRoute(routeId, announce, lockDate){ if(!routeId){ state.selectedRouteId=0; state.selectedRoute=null; renderRouteCalendar(); renderOwnerRoutesSummary(); renderRouteList(); renderRouteDetail(); await loadReports(); return; } try{ state.selectedRouteId=parseInt(routeId,10)||0; const cached=(state.routeAgenda||state.routes||[]).find(r=>String(r.id)===String(routeId)); if(lockDate && cached && cached.date) setRouteDateLock(String(cached.date), cached.id); state.selectedRoute=await j(api+'routes/'+routeId); renderRouteCalendar(); renderOwnerRoutesSummary(); renderRouteList(); renderRouteDetail(); await loadReports(); if(announce) setStatus('Rota carregada com sucesso.'); }catch(err){ setStatus(err.message||'Falha ao carregar detalhe da rota.'); } }
  async function loadPortal(withStatus=true){ try{ if(withStatus) setStatus('A atualizar portal...'); const [stats,commercial]=await Promise.all([j(api+'stats?'+paramsForStats().toString()).catch(()=>({by_day:[]})), j(api+'commercial-search?'+paramsForCommercial().toString()).catch(()=>({stats:{}}))]); state.stats=stats||{}; state.commercial=commercial||{}; renderKpis(state.stats); renderCommercialKpis(state.commercial); renderChart(state.stats.by_day||[]); renderRoutesTable(state.stats.by_day||[]); renderAnalytics(state.stats); ensurePortalTableScroll(); await loadRoutesRange(); await loadCampaignPdvs(false); if(!state.selectedRouteId) await loadReports(); refreshExportLinks(); enforcePortalScopeLocks(); lockCommercialPanel(); if(withStatus) setStatus('Portal atualizado.'); }catch(err){ setStatus(err.message||'Falha ao atualizar portal.'); } }
  root.querySelectorAll('.rp-tabbar button').forEach(btn=>btn.addEventListener('click',()=>switchPanel(btn.dataset.panel||'overview')));
  root.querySelector('#rpcp-refresh')?.addEventListener('click',()=>loadPortal(true));
  function bindCampaignButtons(){
    const refresh=root.querySelector('#rpcp-campaign-refresh');
    const save=root.querySelector('#rpcp-campaign-save');
    if(refresh && !refresh.dataset.bound){ refresh.dataset.bound='1'; refresh.addEventListener('click',ev=>{ ev.preventDefault(); ev.stopPropagation(); state.campaign.page=1; loadCampaignPdvs(true); }); }
    if(save && !save.dataset.bound){ save.dataset.bound='1'; save.addEventListener('click',ev=>{ ev.preventDefault(); ev.stopPropagation(); saveCampaignPdvs(false); }); }
  }
  bindCampaignButtons();
  root.addEventListener('click',ev=>{
    const refresh=ev.target.closest('#rpcp-campaign-refresh');
    const save=ev.target.closest('#rpcp-campaign-save');
    if(refresh && root.contains(refresh)){ ev.preventDefault(); ev.stopPropagation(); state.campaign.page=1; loadCampaignPdvs(true); return; }
    if(save && root.contains(save)){ ev.preventDefault(); ev.stopPropagation(); saveCampaignPdvs(false); return; }
  }, true);
  [els.campaignQ,els.campaignStatus,els.campaignActive,els.campaignOwner,els.campaignPerPage].forEach(el=>{ if(!el) return; const ev=el.tagName==='SELECT'?'change':'input'; let t=null; el.addEventListener(ev,()=>{ clearTimeout(t); t=setTimeout(()=>{ if(el===els.campaignPerPage) state.campaign.perPage=parseInt(el.value||'25',10)||25; state.campaign.page=1; loadCampaignPdvs(true); }, el.tagName==='SELECT'?0:350); }); });
  if(els.unlockRouteDate) els.unlockRouteDate.addEventListener('click',async()=>{ setRouteDateLock('',0); state.selectedRouteId=0; state.selectedRoute=null; renderRouteDetail(); await loadPortal(true); });
  if(els.client){ els.client.addEventListener('change',async()=>{ setRouteDateLock('',0); state.selectedRouteId=0; state.selectedRoute=null; state.ownerRoutesPage=1; state.ownerRoutesMonth='all'; state.routeCalendarMonth=''; state.routeListPage=1; state.campaign.page=1; syncProjects(); await syncOwners(); await syncLocations(); enforcePortalScopeLocks(); const detail={client_id:els.client.value||'',project_id:els.project?.value||'',owner_user_id:els.owner?.value||'',location_id:els.location?.value||''}; root.querySelectorAll('.rp-front-commercial').forEach(fc=>fc.dispatchEvent(new CustomEvent('routespro:scope-change',{detail}))); document.dispatchEvent(new CustomEvent('routespro:scope-change',{detail})); refreshPerformanceDashboard(); loadPortal(true); }); }
  if(els.project){ syncProjects(); els.project.addEventListener('change',async()=>{ setRouteDateLock('',0); state.selectedRouteId=0; state.selectedRoute=null; state.ownerRoutesPage=1; state.ownerRoutesMonth='all'; state.routeCalendarMonth=''; state.routeListPage=1; state.campaign.page=1; await syncOwners(); await syncLocations(); const detail={client_id:els.client?.value||'',project_id:els.project.value||'',owner_user_id:els.owner?.value||'',location_id:els.location?.value||''}; root.querySelectorAll('.rp-front-commercial').forEach(fc=>fc.dispatchEvent(new CustomEvent('routespro:scope-change',{detail}))); document.dispatchEvent(new CustomEvent('routespro:scope-change',{detail})); refreshPerformanceDashboard(); enforcePortalScopeLocks(); loadPortal(true); }); }
  if(els.owner) els.owner.addEventListener('change',async()=>{ setRouteDateLock('',0); state.selectedRouteId=0; state.selectedRoute=null; state.ownerRoutesPage=1; state.ownerRoutesMonth='all'; state.routeCalendarMonth=''; state.routeListPage=1; state.campaign.page=1; await syncLocations(); refreshPerformanceDashboard(); loadPortal(true); });
  if(els.location) els.location.addEventListener('change',()=>{ syncLocationSearchText(); renderLocationOptions(); state.selectedRouteId=0; state.selectedRoute=null; state.routeListPage=1; loadPortal(true); });
  if(els.locationSearch){ els.locationSearch.addEventListener('focus',()=>openLocationPicker(true)); els.locationSearch.addEventListener('click',()=>openLocationPicker(true)); els.locationSearch.addEventListener('input',()=>{ renderLocationOptions(); openLocationPicker(true); if(String(els.locationSearch.value||'').trim()==='' && els.location&&els.location.value){ clearLocation(false); } }); els.locationSearch.addEventListener('keydown',ev=>{ if(ev.key==='Enter'){ ev.preventDefault(); selectLocationFromText(els.locationSearch.value); } else if(ev.key==='Escape'){ openLocationPicker(false); syncLocationSearchText(); } else if(ev.key==='ArrowDown'){ ev.preventDefault(); openLocationPicker(true); const first=els.locationOptions?.querySelector('.rp-search-option'); if(first) first.focus(); } }); window.addEventListener('resize',placeLocationPicker); window.addEventListener('scroll',()=>{ if(els.locationPicker?.classList.contains('open')) placeLocationPicker(); }, true); }
  if(els.locationOptions){ els.locationOptions.addEventListener('mousedown',ev=>{ ev.preventDefault(); const btn=ev.target.closest('.rp-search-option'); if(!btn) return; const val=btn.dataset.value||''; if(!val){ clearLocation(); openLocationPicker(false); return; } const opt=locationOptions().find(o=>String(o.value)===String(val)); chooseLocation(val, opt?opt.text:btn.textContent); }); els.locationOptions.addEventListener('keydown',ev=>{ const btn=ev.target.closest('.rp-search-option'); if(!btn) return; if(ev.key==='Enter'||ev.key===' '){ ev.preventDefault(); btn.dispatchEvent(new MouseEvent('mousedown',{bubbles:true,cancelable:true})); } else if(ev.key==='Escape'){ openLocationPicker(false); els.locationSearch?.focus(); } }); }
  if(els.locationClear){ els.locationClear.addEventListener('click',ev=>{ ev.preventDefault(); clearLocation(); openLocationPicker(false); }); }
  document.addEventListener('click',ev=>{ if(els.locationPicker && !els.locationPicker.contains(ev.target)) openLocationPicker(false); });
  if(els.from) els.from.addEventListener('change',async()=>{ if(state.routeDateLocked) return; state.selectedRouteId=0; state.selectedRoute=null; state.routeListPage=1; state.campaign.page=1; await syncLocations(); refreshPerformanceDashboard(); loadPortal(true); });
  if(els.to) els.to.addEventListener('change',async()=>{ if(state.routeDateLocked) return; state.selectedRouteId=0; state.selectedRoute=null; state.routeListPage=1; state.campaign.page=1; await syncLocations(); refreshPerformanceDashboard(); loadPortal(true); });
  function refreshExportLinks(){
    const disabled=!exportNonce;
    const map=[[els.exportCsv,'csv'],[els.exportXls,'xls'],[els.exportPdf,'pdf'],[els.analyticsExportCsv,'csv'],[els.analyticsExportXls,'xls'],[els.analyticsExportPdf,'pdf']];
    map.forEach(([btn,format])=>{
      if(!btn) return;
      btn.setAttribute('aria-disabled', disabled ? 'true' : 'false');
      btn.style.opacity=disabled?'0.55':'1';
      btn.style.pointerEvents=disabled?'none':'auto';
      btn.style.cursor=disabled?'not-allowed':'pointer';
      btn.style.position='relative';
      btn.style.zIndex='9999';
      btn.style.filter='none';
      btn.style.visibility='visible';
      btn.title=disabled?'Sessão expirada para exportação. Atualiza a página.':'Exportar relatório filtrado em '+format.toUpperCase();
      const href = disabled ? '#' : exportUrl(format);
      btn.setAttribute('href', href);
      btn.setAttribute('target', '_blank');
      btn.setAttribute('rel', 'noopener');
    });
  }
  [els.exportCsv, els.exportXls, els.exportPdf, els.analyticsExportCsv, els.analyticsExportXls, els.analyticsExportPdf].forEach(btn=>{
    if(!btn) return;
    btn.addEventListener('click', function(ev){
      refreshExportLinks();
      if(btn.getAttribute('href')==='#'){
        ev.preventDefault();
        setStatus('Sessão expirada para exportação. Atualiza a página.');
      }
    });
  });
  enforcePortalScopeLocks();
  await syncOwners();
  await syncLocations();
  lockCommercialPanel();
  await refreshPerformanceDashboard();
  await loadPortal(false);
  ensurePortalTableScroll();
})();
</script>
